// ElevenLabs post-call webhook payload
const body = $input.first().json.body || $input.first().json;

// Temel alanlar
const conversationId = body.conversation_id || '';
const agentId        = body.agent_id || '';
const callDuration   = body.call_duration_secs || 0;
const transcript     = body.transcript || [];
const callSuccess    = body.call_successful || false;

// Telefon numarası
const metadata   = body.metadata || {};
const clientData = body.conversation_initiation_client_data || {};
const rawPhone   = metadata.phone_number
  || clientData.to_number
  || body.to_number
  || '';
const whatsappNumber = rawPhone.replace(/\D/g, '');

// Data collection
const dc = body.data_collection_results || {};
const customerName    = dc.customer_name?.value    || '';
const appointmentDate = dc.appointment_date?.value || '';
const appointmentTime = dc.appointment_time?.value || '';
const rawAddr         = dc.appointment_address?.value || '';
let   appointmentLat  = dc.appointment_lat?.value  ? parseFloat(dc.appointment_lat.value)  : null;
let   appointmentLng  = dc.appointment_lng?.value  ? parseFloat(dc.appointment_lng.value)  : null;

// ── Adres koordinat mı? Örn: "39.994784, 32.768634" ──
// ElevenLabs bazen adres alanına koordinat yazıyor.
const COORD_RE = /^\s*(-?\d{1,3}\.\d+)\s*,\s*(-?\d{1,3}\.\d+)\s*$/;
const coordMatch = rawAddr.match(COORD_RE);
let appointmentAddr = rawAddr;

if (coordMatch) {
  // Koordinatları parse et, adres metnini boşalt
  appointmentLat = parseFloat(coordMatch[1]);
  appointmentLng = parseFloat(coordMatch[2]);
  appointmentAddr = ''; // harita mesajıyla gönderilecek
}

// Süre formatı
const mins = Math.floor(callDuration / 60);
const secs = callDuration % 60;
const durationText = mins > 0 ? `${mins} dk ${secs} sn` : `${secs} sn`;

return [{
  json: {
    conversationId,
    agentId,
    callDuration,
    durationText,
    callSuccess,
    whatsappNumber,
    customerName,
    appointmentDate,
    appointmentTime,
    appointmentAddr,
    appointmentLat,
    appointmentLng,
    hasAppointment: !!(appointmentDate || appointmentTime || appointmentLat),
    hasLocation: !!(appointmentLat && appointmentLng)
  }
}];

// Supabase'den gelen aktif şablon
const templates = $input.first().json;
const callData  = $('Veriyi İşle').first().json;

// ─── Fallback: Supabase'de aktif şablon yoksa bunu kullan ───
const FALLBACK = [
  '━━━━━━━━━━━━━━━━━━━━━',
  '🤖 *LUERA CallFlow*',
  '━━━━━━━━━━━━━━━━━━━━━',
  '',
  'Merhaba *{{isim}}!* 👋',
  '',
  'AI asistanımızla görüşmeniz başarıyla tamamlandı. ✅',
  '⏱ Görüşme süresi: _{{sure}}_',
  '{{randevu_bolumu}}',
  '',
  'Herhangi bir sorunuz için bizi aramaktan çekinmeyin. 😊',
  '',
  '_Teşekkürler, görüşmek üzere!_ 🙏',
  '*LUERA Ekibi*'
].join('\n');

// Şablon içeriğini belirle (Supabase'den "message" veya "content" alanı)
let templateContent = '';
if (Array.isArray(templates) && templates.length > 0) {
  const tpl = templates[0];
  templateContent = tpl.message || tpl.content || '';
}
if (!templateContent.trim()) {
  templateContent = FALLBACK;
}

// Randevu bölümü — sadece veri varsa göster
let randevuBolumu = '';
if (callData.appointmentDate || callData.appointmentTime || callData.hasLocation) {
  randevuBolumu = '\n📅 *Randevu Bilgileriniz*\n──────────────────────';
  if (callData.appointmentDate) randevuBolumu += `\n📆 Tarih: *${callData.appointmentDate}*`;
  if (callData.appointmentTime) randevuBolumu += `\n🕐 Saat: *${callData.appointmentTime}*`;
  if (callData.appointmentAddr) {
    randevuBolumu += `\n📍 Adres: ${callData.appointmentAddr}`;
  } else if (callData.hasLocation) {
    randevuBolumu += `\n📍 _Konum aşağıda harita olarak paylaşıldı_ 👇`;
  }
}

// Müşteri adı — boşsa nazik fallback
const isim = (callData.customerName || '').trim() || 'Değerli Müşterimiz';

// Değişken yerine koy (her iki adres formatını da destekle)
const messageText = templateContent
  .replace(/\{\{isim\}\}/gi, isim)
  .replace(/\{\{sure\}\}/gi, callData.durationText || '')
  .replace(/\{\{randevu_tarihi\}\}/gi, callData.appointmentDate || '')
  .replace(/\{\{randevu_saati\}\}/gi, callData.appointmentTime || '')
  .replace(/\{\{randevu_adresi\}\}/gi, callData.appointmentAddr || '')
  .replace(/\{\{adres\}\}/gi, callData.appointmentAddr || '')
  .replace(/\{\{randevu_bolumu\}\}/gi, randevuBolumu)
  .replace(/\{\{konusma_id\}\}/gi, callData.conversationId || '');

return [{
  json: {
    ...callData,
    messageText
  }
}];

